import { z } from "zod";
import {
  encodeDeployData,
  parseUnits,
  isAddress,
  type Hex,
} from "viem";
import { getEvmClient } from "../chains/config.js";

const ERC20_BYTECODE =
  "";

export const deployTokenSchema = z.object({
  chain: z.enum(["celo", "base"]).describe("EVM chain to deploy on"),
  name: z.string().describe("Token name (e.g. 'My Token')"),
  symbol: z.string().max(10).describe("Token symbol (e.g. 'MTK')"),
  decimals: z.number().int().min(0).max(18).default(18),
  totalSupply: z.string().describe("Total supply (e.g. '1000000')"),
  ownerAddress: z
    .string()
    .describe("Address that will receive the initial supply"),
});

export type DeployTokenInput = z.infer<typeof deployTokenSchema>;

export interface DeployTokenTx {
  chain: string;
  type: "evm-deploy";
  data: Hex;
  nonce: number;
  gasLimit: string;
  description: string;
  ownerAddress: string;
}

export async function prepareDeployToken(
  input: DeployTokenInput
): Promise<DeployTokenTx> {
  const { chain, name, symbol, decimals, totalSupply, ownerAddress } = input;

  if (!isAddress(ownerAddress)) {
    throw new Error(`Invalid owner address: ${ownerAddress}`);
  }

  const client = getEvmClient(chain);
  const supply = parseUnits(totalSupply, decimals);
  const nonce = await client.getTransactionCount({
    address: ownerAddress as `0x${string}`,
  });

  const abi = [
    {
      type: "constructor",
      inputs: [
        { name: "name_", type: "string" },
        { name: "symbol_", type: "string" },
        { name: "decimals_", type: "uint8" },
        { name: "initialSupply", type: "uint256" },
        { name: "owner", type: "address" },
      ],
    },
  ] as const;

  const data = encodeDeployData({
    abi,
    bytecode: ERC20_BYTECODE as Hex,
    args: [name, symbol, decimals, supply, ownerAddress as `0x${string}`],
  });

  const gasLimit = await client
    .estimateGas({
      account: ownerAddress as `0x${string}`,
      data,
    })
    .catch(() => 3_000_000n);

  return {
    chain,
    type: "evm-deploy",
    data,
    nonce,
    gasLimit: gasLimit.toString(),
    ownerAddress,
    description: `Deploy ERC-20 "${name}" (${symbol}) with ${totalSupply} supply on ${chain}`,
  };
}
